import{_ as e,o as a,c as i,ao as l}from"./chunks/framework.BHAH78NU.js";const p=JSON.parse('{"title":"Backend And Algorithm Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"backend-algorithm-roadmap.md","filePath":"backend-algorithm-roadmap.md","lastUpdated":null}'),r={name:"backend-algorithm-roadmap.md"};function d(n,t,s,o,c,g){return a(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="Backend-And-Algorithm-Roadmap" tabindex="-1">Backend And Algorithm Roadmap <a class="header-anchor" href="#Backend-And-Algorithm-Roadmap" aria-label="Permalink to &quot;Backend And Algorithm Roadmap {#Backend-And-Algorithm-Roadmap}&quot;">​</a></h1><p>This page records the Julia execution strategy behind the broader genomics, QTL, GLLVM, GPU, and HPC roadmap.</p><p>Status: roadmap. <code>HSquared.jl</code> currently exposes backend marker types, <code>HSControl</code>, and <code>backend_info()</code> as status and control metadata only. It does not dispatch model fitting to GPU, probe runtime device availability, benchmark backends, or test CPU/GPU numerical agreement yet.</p><h2 id="Backend-Vocabulary" tabindex="-1">Backend Vocabulary <a class="header-anchor" href="#Backend-Vocabulary" aria-label="Permalink to &quot;Backend Vocabulary {#Backend-Vocabulary}&quot;">​</a></h2><p>The shared R/Julia backend names are:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Julia marker</th><th style="text-align:right;">R/backend name</th><th style="text-align:right;">Current status</th><th style="text-align:right;">Intended first use</th><th style="text-align:right;">Not yet</th></tr></thead><tbody><tr><td style="text-align:right;"><code>CPUBackend()</code></td><td style="text-align:right;"><code>cpu</code></td><td style="text-align:right;">selectable metadata only</td><td style="text-align:right;">trusted baseline for every supported model</td><td style="text-align:right;">production sparse optimizer</td></tr><tr><td style="text-align:right;"><code>ThreadsBackend()</code></td><td style="text-align:right;"><code>threads</code></td><td style="text-align:right;">selectable metadata only</td><td style="text-align:right;">threaded CPU loops, BLAS-heavy dense work, simulation batches</td><td style="text-align:right;">threaded fitting dispatch</td></tr><tr><td style="text-align:right;"><code>CUDABackend()</code></td><td style="text-align:right;"><code>cuda</code></td><td style="text-align:right;">future optional-extension marker</td><td style="text-align:right;">NVIDIA HPC dense marker, factor, and response-matrix workloads</td><td style="text-align:right;">CUDA execution, tests, benchmarks</td></tr><tr><td style="text-align:right;"><code>AMDGPUBackend()</code></td><td style="text-align:right;"><code>amdgpu</code></td><td style="text-align:right;">future optional-extension marker</td><td style="text-align:right;">ROCm/HPC accelerator lane after hardware tests</td><td style="text-align:right;">AMD GPU execution, tests, benchmarks</td></tr><tr><td style="text-align:right;"><code>MetalBackend()</code></td><td style="text-align:right;"><code>metal</code></td><td style="text-align:right;">future optional-extension marker</td><td style="text-align:right;">Mac development smoke tests and dense accelerator experiments</td><td style="text-align:right;">Metal execution, tests, benchmarks</td></tr><tr><td style="text-align:right;"><code>OneAPIBackend()</code></td><td style="text-align:right;"><code>oneapi</code></td><td style="text-align:right;">future optional-extension marker</td><td style="text-align:right;">Intel accelerator experiments where hardware exists</td><td style="text-align:right;">oneAPI execution, tests, benchmarks</td></tr><tr><td style="text-align:right;"><code>AutoBackend()</code></td><td style="text-align:right;"><code>auto</code></td><td style="text-align:right;">selection metadata only</td><td style="text-align:right;">later benchmark- and capability-aware default choice</td><td style="text-align:right;">runtime probing, auto selection</td></tr></tbody></table><p><code>backend_info()</code> is the authoritative status diagnostic for the current package. All backend rows are selectable, execution unavailable, and planned.</p><h2 id="Optional-Extension-Policy" tabindex="-1">Optional Extension Policy <a class="header-anchor" href="#Optional-Extension-Policy" aria-label="Permalink to &quot;Optional Extension Policy {#Optional-Extension-Policy}&quot;">​</a></h2><p>CPU must remain reliable and always available. GPU packages must not become hard dependencies for ordinary animal models.</p><p>Potential Julia extension layout:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ext/HSquaredCUDAExt.jl</span></span>
<span class="line"><span>ext/HSquaredAMDGPUExt.jl</span></span>
<span class="line"><span>ext/HSquaredMetalExt.jl</span></span>
<span class="line"><span>ext/HSquaredOneAPIExt.jl</span></span></code></pre></div><p>The extension gate is stricter than type availability:</p><ol><li><p>package extension loads;</p></li><li><p>tiny numerical fixture passes;</p></li><li><p>backend-specific diagnostics report device, precision, and memory;</p></li><li><p>CPU/backend agreement test passes at declared tolerance;</p></li><li><p>public claim row and validation-debt row are updated.</p></li></ol><p>Until those gates exist, backend names are roadmap vocabulary only.</p><h2 id="Work-Placement" tabindex="-1">Work Placement <a class="header-anchor" href="#Work-Placement" aria-label="Permalink to &quot;Work Placement {#Work-Placement}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Work class</th><th style="text-align:right;">Primary backend</th><th style="text-align:right;">Reason</th><th style="text-align:right;">Current status</th></tr></thead><tbody><tr><td style="text-align:right;">Pedigree validation, sorting, ID recoding</td><td style="text-align:right;">CPU</td><td style="text-align:right;">irregular graph and table work</td><td style="text-align:right;">partially implemented on CPU</td></tr><tr><td style="text-align:right;">Sparse <code>Ainv</code> construction</td><td style="text-align:right;">CPU</td><td style="text-align:right;">sparse pedigree graph structure</td><td style="text-align:right;">implemented CPU utility</td></tr><tr><td style="text-align:right;">Symbolic sparse factorization</td><td style="text-align:right;">CPU</td><td style="text-align:right;">irregular sparse structure and mature CPU libraries</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Small univariate animal models</td><td style="text-align:right;">CPU</td><td style="text-align:right;">transfer overhead dominates accelerator benefit</td><td style="text-align:right;">experimental dense and supplied-variance sparse paths</td></tr><tr><td style="text-align:right;">Sparse MME solves</td><td style="text-align:right;">CPU first, hybrid later</td><td style="text-align:right;">sparse direct/iterative solvers need robust preconditioners</td><td style="text-align:right;">supplied-variance solve only</td></tr><tr><td style="text-align:right;">Dense genomic matrix operations</td><td style="text-align:right;">GPU-friendly</td><td style="text-align:right;">large dense matrix products and reductions</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Marker matrix multiplication</td><td style="text-align:right;">GPU-friendly</td><td style="text-align:right;">high arithmetic intensity and batch structure</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Factor-analytic G matrices</td><td style="text-align:right;">CPU now, GPU-friendly later</td><td style="text-align:right;">repeated low-rank dense updates</td><td style="text-align:right;">experimental dense validation-scale engine path exists; GPU/performance path planned</td></tr><tr><td style="text-align:right;">GLLVM likelihood blocks</td><td style="text-align:right;">GPU-friendly later</td><td style="text-align:right;">large response matrices and low-rank factors</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Simulation, bootstrap, cross-validation</td><td style="text-align:right;">GPU-friendly later</td><td style="text-align:right;">independent batches</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Single-step with sparse <code>A</code> and dense <code>G</code></td><td style="text-align:right;">hybrid</td><td style="text-align:right;">sparse pedigree plus dense genomic block</td><td style="text-align:right;">planned</td></tr></tbody></table><p>Do not assume GPU is faster. Backend choice must be benchmarked on the target model, data shape, precision, and hardware.</p><h2 id="Algorithm-Leads" tabindex="-1">Algorithm Leads <a class="header-anchor" href="#Algorithm-Leads" aria-label="Permalink to &quot;Algorithm Leads {#Algorithm-Leads}&quot;">​</a></h2><p>These are development leads, not implemented algorithms unless a capability row says otherwise.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Lead</th><th style="text-align:right;">Intended role</th><th style="text-align:right;">First gate</th><th style="text-align:right;">Current status</th></tr></thead><tbody><tr><td style="text-align:right;">Sparse Henderson MME</td><td style="text-align:right;">Phase 1 equation system and BLUP/EBV path</td><td style="text-align:right;">Mrode-style supplied-variance and fitted-model fixtures</td><td style="text-align:right;">supplied-variance solve exists</td></tr><tr><td style="text-align:right;">Sparse REML/ML objective</td><td style="text-align:right;">production univariate animal-model likelihood</td><td style="text-align:right;">dense/sparse equality plus Mrode validation</td><td style="text-align:right;">supplied-variance sparse REML identity exists</td></tr><tr><td style="text-align:right;">AI-REML</td><td style="text-align:right;">production variance-component optimizer candidate</td><td style="text-align:right;">stable sparse objective, score, information, and step safeguards</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">EM or PX-EM warm starts</td><td style="text-align:right;">robust starting values for fragile variance components</td><td style="text-align:right;">convergence and bias checks on simulations</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Newton or trust-region refinement</td><td style="text-align:right;">faster local convergence after stable starts</td><td style="text-align:right;">objective, gradient, information consistency checks</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">PCG and block preconditioners</td><td style="text-align:right;">huge mixed-model systems</td><td style="text-align:right;">identical estimand against direct solves on smaller fixtures</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Takahashi selected inversion</td><td style="text-align:right;">selected inverse entries, PEV, and reliability after sparse factorization</td><td style="text-align:right;">factorization exists and selected entries match dense inverse on tiny fixtures</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">Woodbury and determinant lemma</td><td style="text-align:right;">low-rank G matrices and GLLVM-style likelihood blocks</td><td style="text-align:right;">equality to dense path on small matrices</td><td style="text-align:right;">planned</td></tr><tr><td style="text-align:right;">APY approximation</td><td style="text-align:right;">large genomic and single-step relationship inverse approximation</td><td style="text-align:right;">genomic/single-step phase with comparator evidence</td><td style="text-align:right;">planned</td></tr></tbody></table><p>Local reference rule:</p><ul><li><p><code>DRM.jl/src/takahashi_selinv.jl</code> is an algorithm lead for selected sparse inverse entries after <code>HSquared.jl</code> has sparse factorizations.</p></li><li><p><code>GLLVM.jl/src/fit.jl</code> and <code>GLLVM.jl/src/structured_schur.jl</code> are design leads for low-rank, profiled, Woodbury, and structured precision machinery.</p></li></ul><p>These are not automatic copy sources. Any code reuse needs explicit license, provenance, tests, and fit-for-purpose review.</p><h2 id="Numerical-Policy" tabindex="-1">Numerical Policy <a class="header-anchor" href="#Numerical-Policy" aria-label="Permalink to &quot;Numerical Policy {#Numerical-Policy}&quot;">​</a></h2><p>Default precision should be <code>Float64</code> for REML and publication-quality variance components.</p><p><code>Float32</code> and mixed precision are later accelerator options for exploratory huge GLLVM, genomic, and scan workloads. They need explicit agreement tests, documented tolerances, seed handling, and nondeterminism notes before public use.</p><p>Every backend comparison should record:</p><ul><li><p>hardware and operating system;</p></li><li><p>backend package and version;</p></li><li><p>precision;</p></li><li><p>records, animals, traits, markers, and nonzeros;</p></li><li><p>wall time and memory;</p></li><li><p>device memory where relevant;</p></li><li><p>log-likelihood, parameter, EBV, heritability, and G-matrix differences;</p></li><li><p>convergence status and gradient diagnostics.</p></li></ul><h2 id="Claim-Gates" tabindex="-1">Claim Gates <a class="header-anchor" href="#Claim-Gates" aria-label="Permalink to &quot;Claim Gates {#Claim-Gates}&quot;">​</a></h2><p>Allowed wording today:</p><ul><li><p>backend names are recorded;</p></li><li><p><code>backend_info()</code> reports planned/unavailable backend status;</p></li><li><p>CPU is the trusted default;</p></li><li><p>GPU, APY, AI-REML, Takahashi selected inverse, and GLLVM acceleration are roadmap targets.</p></li></ul><p>Blocked wording today:</p><ul><li><p>GPU execution works;</p></li><li><p>backend auto-selection works;</p></li><li><p>CPU and GPU agree;</p></li><li><p><code>HSquared.jl</code> is faster than ASReml, JWAS, GLLVM.jl, or other comparators;</p></li><li><p>APY, AI-REML, or Takahashi selected inversion is implemented;</p></li><li><p>genomic/QTL/GLLVM models are fitted.</p></li></ul><p>Rose audit rule: any future backend or algorithm promotion must update tests, Documenter, capability status, validation debt, the public claims register, check-log evidence, and an after-task report in the same slice.</p>`,34)])])}const y=e(r,[["render",d]]);export{p as __pageData,y as default};
